"use client";

import React, { createContext, useContext, useState, useCallback, useEffect, type ReactNode } from "react";
import {
  validateDemoCredentials,
  isDemoMode,
  type DemoUser,
} from "./demo-store";

interface DemoAuthState {
  user: DemoUser | null;
  loading: boolean;
  isDemo: boolean;
  signIn: (email: string, password: string) => Promise<{ error: string | null }>;
  signOut: () => void;
  oneClickDemo: () => Promise<{ error: string | null }>;
}

const DemoAuthContext = createContext<DemoAuthState>({
  user: null,
  loading: true,
  isDemo: false,
  signIn: async () => ({ error: "not initialized" }),
  signOut: () => {},
  oneClickDemo: async () => ({ error: "not initialized" }),
});

export function useDemoAuth() {
  return useContext(DemoAuthContext);
}

export function DemoAuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<DemoUser | null>(null);
  const [loading, setLoading] = useState(true);
  const demoActive = isDemoMode();

  useEffect(() => {
    if (demoActive) {
      const stored = sessionStorage.getItem("demo_user");
      if (stored) {
        try {
          setUser(JSON.parse(stored));
        } catch {
          sessionStorage.removeItem("demo_user");
        }
      }
    }
    setLoading(false);
  }, [demoActive]);

  const signIn = useCallback(async (email: string, password: string) => {
    if (!demoActive) return { error: "Demo mode not available" };
    const u = validateDemoCredentials(email, password);
    if (!u) return { error: "Invalid credentials. Try demo@demo.app / demo123" };
    setUser(u);
    sessionStorage.setItem("demo_user", JSON.stringify(u));
    return { error: null };
  }, [demoActive]);

  const oneClickDemo = useCallback(async () => {
    return signIn("demo@demo.app", "demo123");
  }, [signIn]);

  const signOut = useCallback(() => {
    setUser(null);
    sessionStorage.removeItem("demo_user");
  }, []);

  return (
    <DemoAuthContext.Provider value={{ user, loading, isDemo: demoActive, signIn, signOut, oneClickDemo }}>
      {children}
    </DemoAuthContext.Provider>
  );
}

import { createBrowserClient } from "@supabase/ssr";
import type { AuthError } from "@supabase/supabase-js";
import { isDemoMode, validateDemoCredentials } from "@/lib/demo/demo-store";

export async function signIn(email: string, password: string): Promise<{ error: string | null }> {
  if (isDemoMode()) {
    const user = validateDemoCredentials(email, password);
    if (!user) return { error: "Invalid email or password. Try demo@demo.app / demo123" };
    sessionStorage.setItem("demo_user", JSON.stringify(user));
    return { error: null };
  }

  const supabase = createBrowserClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
  );
  const { error } = await supabase.auth.signInWithPassword({ email, password });
  return { error: error?.message || null };
}

export async function signUp(email: string, password: string, fullName: string): Promise<{ error: string | null }> {
  if (isDemoMode()) {
    return { error: "Sign up is disabled in demo mode. Use demo@demo.app / demo123 to sign in." };
  }

  const supabase = createBrowserClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
  );
  const { error } = await supabase.auth.signUp({
    email,
    password,
    options: { data: { full_name: fullName } },
  });
  return { error: error?.message || null };
}

export async function signOut(): Promise<void> {
  if (isDemoMode()) {
    sessionStorage.removeItem("demo_user");
    return;
  }

  const supabase = createBrowserClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
  );
  await supabase.auth.signOut();
}

export async function getSession() {
  if (isDemoMode()) {
    if (typeof window !== "undefined") {
      const stored = sessionStorage.getItem("demo_user");
      if (stored) {
        try {
          return { session: { user: JSON.parse(stored) } };
        } catch {
          return { session: null };
        }
      }
    }
    return { session: null };
  }

  const supabase = createBrowserClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
  );
  return supabase.auth.getSession();
}

"use client";

import { useState, useCallback } from "react";

export interface Toast {
  id: string;
  message: string;
  type: "success" | "error" | "info";
}

export function useToast() {
  const [toasts, setToasts] = useState<Toast[]>([]);

  const addToast = useCallback((message: string, type: Toast["type"] = "info") => {
    const id = Math.random().toString(36).slice(2);
    setToasts((prev) => [...prev, { id, message, type }]);
    setTimeout(() => {
      setToasts((prev) => prev.filter((t) => t.id !== id));
    }, 4000);
  }, []);

  const removeToast = useCallback((id: string) => {
    setToasts((prev) => prev.filter((t) => t.id !== id));
  }, []);

  return { toasts, addToast, removeToast };
}

