        <div className="w-full max-w-md text-center">
          <div className="font-heading text-3xl text-primary mb-4">ATLASHAVEN</div>
          <div className="bg-surface border border-border rounded-xl p-8">
            <h2 className="font-heading text-2xl text-text_primary mb-2">Password Reset</h2>
            <p className="text-text_secondary text-sm mb-6">
              Your password has been reset successfully. You can now sign in with your new password.
            </p>
            <Link
              href="/sign-in"
              className="inline-block bg-primary text-background px-6 py-2.5 rounded-lg font-semibold hover:bg-primary/90 transition-colors"
            >
              Sign In
            </Link>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex items-center justify-center bg-background px-4">
      <div className="w-full max-w-md">
        <div className="text-center mb-8">
          <Link href="/" className="font-heading text-3xl text-primary">
            ATLASHAVEN
          </Link>
          <p className="mt-2 text-text_secondary">Set new password</p>
        </div>
        <div className="bg-surface border border-border rounded-xl p-8">
          <form onSubmit={handleSubmit} className="space-y-5">
            {error && (
              <div className="bg-red-500/10 border border-red-500/30 rounded-lg p-3 text-red-400 text-sm">
                {error}
              </div>
            )}
            <div>
              <label htmlFor="password" className="block text-sm font-medium text-text_primary mb-1.5">
                New Password
              </label>
              <input
                id="password"
                type="password"
                required
                minLength={6}
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full bg-background border border-border rounded-lg px-3 py-2 text-text_primary text-sm placeholder:text-text_secondary focus:outline-none focus:border-primary transition-colors"
                placeholder="••••••••"
              />
            </div>
            <div>
              <label htmlFor="confirmPassword" className="block text-sm font-medium text-text_primary mb-1.5">
                Confirm Password
              </label>
              <input
                id="confirmPassword"
                type="password"
                required
                value={confirmPassword}
                onChange={(e) => setConfirmPassword(e.target.value)}
                className="w-full bg-background border border-border rounded-lg px-3 py-2 text-text_primary text-sm placeholder:text-text_secondary focus:outline-none focus:border-primary transition-colors"
                placeholder="••••••••"
              />
            </div>
            <button
              type="submit"
              disabled={loading}
              className="w-full bg-primary text-background py-3 rounded-lg font-semibold hover:bg-primary/90 transition-colors disabled:opacity-50"
            >
              {loading ? "Resetting..." : "Reset Password"}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
}

"use client";

import { type ReactNode, useState } from "react";
import { useRouter } from "next/navigation";
import { useDemoAuth } from "@/lib/demo/demo-auth";
import { TopNav } from "@/components/layout/top-nav";
import { MobileDrawer } from "@/components/nav/drawer";

export default function DashboardLayout({ children }: { children: ReactNode }) {
  const { user, loading, isDemo } = useDemoAuth();
  const router = useRouter();
  const [drawerOpen, setDrawerOpen] = useState(false);

  // Allow render if demo user exists OR if we're not in demo mode (Supabase handles auth)
  if (loading) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <div className="text-text_secondary">Loading...</div>
      </div>
    );
  }

  if (!isDemo && !user) {
    // In non-demo mode, middleware handles auth redirect
    return <>{children}</>;
  }

  if (isDemo && !user) {
    router.push("/sign-in");
    return null;
  }

  return (
    <div className="min-h-screen bg-background">
      <TopNav />
      <MobileDrawer open={drawerOpen} onClose={() => setDrawerOpen(false)} />
      <main className="max-w-7xl mx-auto">{children}</main>
    </div>
  );
}

