"use client";

import { useState } from "react";
import Link from "next/link";
import { getDemoProposals, getDemoContacts } from "@/lib/demo/demo-store";
import { Button } from "@/components/ui/buttons";
import { Card } from "@/components/ui/cards";
import { useToastContext } from "@/components/ui/toast";
import { jsPDF } from "jspdf";

const statusColors: Record<string, string> = {
  Draft: "bg-text_secondary/10 text-text_secondary border-text_secondary/30",
  Sent: "bg-primary/10 text-primary border-primary/30",
  Accepted: "bg-green-500/10 text-green-400 border-green-500/30",
  Rejected: "bg-red-500/10 text-red-400 border-red-500/30",
};

export default function ProposalsPage() {
  const { addToast } = useToastContext();
  const [proposals] = useState(() => getDemoProposals());
  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState<string>("All");
  const contacts = getDemoContacts();

  const filtered = proposals.filter((p) => {
    const matchesSearch = p.name.toLowerCase().includes(search.toLowerCase());
    const matchesStatus = statusFilter === "All" || p.status === statusFilter;
    return matchesSearch && matchesStatus;
  });

  const activeProposals = proposals.filter((p) => p.status === "Sent" || p.status === "Accepted");
  const totalPipeline = activeProposals.reduce((s, p) => s + p.totalAmount, 0);

  const downloadPDF = (p: typeof proposals[0]) => {
    const doc = new jsPDF();
    const contact = contacts.find((c) => c.id === p.contactId);

    doc.setFont("helvetica", "bold");
    doc.setFontSize(20);
    doc.text("ATLASHAVEN", 20, 20);
    doc.setFontSize(16);
    doc.text("Proposal", 20, 32);

    doc.setFont("helvetica", "normal");
    doc.setFontSize(11);
    doc.text(`Proposal: ${p.name}`, 20, 48);
    doc.text(`Status: ${p.status}`, 20, 56);
    if (contact) doc.text(`Client: ${contact.name} · ${contact.company}`, 20, 64);
    doc.text(`Date: ${new Date(p.createdAt).toLocaleDateString()}`, 20, 72);

    doc.setFontSize(10);
    const descLines = doc.splitTextToSize(p.description, 170);
    doc.text(descLines, 20, 86);

    // Line items table
    let y = 100 + (descLines.length * 5);
    doc.setFont("helvetica", "bold");
    doc.text("Description", 20, y);
    doc.text("Qty", 120, y);
    doc.text("Unit Price", 145, y);
    doc.text("Total", 175, y);
    y += 6;
    doc.setDrawColor(200);
    doc.line(20, y, 190, y);
    y += 8;

    doc.setFont("helvetica", "normal");
    p.lineItems.forEach((item) => {
      doc.text(item.description.substring(0, 40), 20, y);
      doc.text(String(item.quantity), 120, y);
      doc.text(`$${item.unitPrice.toLocaleString()}`, 145, y);
      doc.text(`$${(item.quantity * item.unitPrice).toLocaleString()}`, 175, y);
      y += 7;
    });

    doc.line(20, y, 190, y);
    y += 8;
    doc.setFont("helvetica", "bold");
    doc.text("Total:", 145, y);
    doc.text(`$${p.totalAmount.toLocaleString()}`, 175, y);

    doc.save(`${p.name.replace(/[^a-zA-Z0-9]/g, "_")}.pdf`);
    addToast("PDF downloaded", "success");
  };

  return (
    <div className="p-6 md:p-8">
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4 mb-6">
        <div>
          <h1 className="font-heading text-3xl text-text_primary">Proposals</h1>
          <p className="text-text_secondary mt-1">Track and manage client proposals.</p>
        </div>
        <Link href="/dashboard/proposals/new">
          <Button variant="primary">+ New Proposal</Button>
        </Link>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-6">
        <div className="bg-surface border border-border rounded-xl p-5">
          <p className="text-text_secondary text-sm">Total Pipeline</p>
          <p className="font-heading text-3xl text-text_primary mt-1">${totalPipeline.toLocaleString()}</p>
        </div>
        <div className="bg-surface border border-green-500/30 rounded-xl p-5">
          <p className="text-text_secondary text-sm">Accepted</p>
          <p className="font-heading text-3xl text-green-400 mt-1">
            {proposals.filter((p) => p.status === "Accepted").length}
          </p>
        </div>
        <div className="bg-surface border border-primary/30 rounded-xl p-5">
          <p className="text-text_secondary text-sm">Outstanding</p>
          <p className="font-heading text-3xl text-primary mt-1">
            {proposals.filter((p) => p.status === "Sent").length}
          </p>
        </div>
      </div>

      <div className="flex flex-col sm:flex-row gap-3 mb-6">
        <input
          type="text"
          placeholder="Search proposals..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="flex-1 bg-surface border border-border rounded-lg px-4 py-2 text-text_primary text-sm placeholder:text-text_secondary focus:outline-none focus:border-primary"
        />
        <select
          value={statusFilter}
          onChange={(e) => setStatusFilter(e.target.value)}
          className="bg-surface border border-border rounded-lg px-4 py-2 text-text_primary text-sm focus:outline-none focus:border-primary"
        >
          <option value="All">All Statuses</option>
          <option value="Draft">Draft</option>
          <option value="Sent">Sent</option>
          <option value="Accepted">Accepted</option>
          <option value="Rejected">Rejected</option>
        </select>
      </div>

      <div className="space-y-4">
        {filtered.map((p) => {
          const contact = contacts.find((c) => c.id === p.contactId);
          return (
            <Card key={p.id}>
              <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3">
                <div className="flex-1">
                  <Link
                    href={`/dashboard/proposals/${p.id}/edit`}
                    className="font-heading text-lg text-text_primary hover:text-primary transition-colors"
                  >
                    {p.name}
                  </Link>
                  <p className="text-text_secondary text-sm mt-0.5">
                    {contact?.company || "No contact"} · Created {new Date(p.createdAt).toLocaleDateString()}
                  </p>
                  <p className="text-text_secondary text-xs mt-1 line-clamp-1">{p.description}</p>
                </div>
                <div className="flex items-center gap-3 self-end sm:self-center">
                  <span className="font-heading text-xl text-text_primary">
                    ${p.totalAmount.toLocaleString()}
                  </span>
                  <span className={`text-xs px-2.5 py-1 rounded-full border font-medium ${statusColors[p.status]}`}>
                    {p.status}
                  </span>
                  <div className="flex gap-1">
                    <Link href={`/dashboard/proposals/${p.id}/edit`}>
                      <Button variant="ghost" size="sm">Edit</Button>
                    </Link>
                    <Button variant="ghost" size="sm" onClick={() => downloadPDF(p)}>
                      PDF
                    </Button>
                  </div>
                </div>
              </div>
            </Card>
          );
        })}
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import { addDemoProposal, getDemoContacts } from "@/lib/demo/demo-store";
import { useToastContext } from "@/components/ui/toast";
import { Button } from "@/components/ui/buttons";
import { Card } from "@/components/ui/cards";

interface LineItem {
  description: string;
  quantity: number;
  unitPrice: number;
}

export default function NewProposalPage() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const prefillContactId = searchParams.get("contactId");
  const { addToast } = useToastContext();

  const contacts = getDemoContacts();

  const [name, setName] = useState("");
  const [description, setDescription] = useState("");
  const [contactId, setContactId] = useState(prefillContactId || "");
  const [lineItems, setLineItems] = useState<LineItem[]>([
    { description: "", quantity: 1, unitPrice: 0 },
  ]);
  const [saving, setSaving] = useState(false);

  const totalAmount = lineItems.reduce((sum, li) => sum + li.quantity * li.unitPrice, 0);

  const addLineItem = () => {
    setLineItems([...lineItems, { description: "", quantity: 1, unitPrice: 0 }]);
  };

  const removeLineItem = (i: number) => {
    if (lineItems.length <= 1) return;
    setLineItems(lineItems.filter((_, idx) => idx !== i));
  };

  const updateLineItem = (i: number, field: keyof LineItem, value: string | number) => {
    const updated = [...lineItems];
    updated[i] = { ...updated[i], [field]: value };
    setLineItems(updated);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim()) { addToast("Proposal name is required", "error"); return; }
    if (lineItems.some((li) => !li.description.trim())) {
      addToast("All line items need descriptions", "error"); return;
    }

    setSaving(true);
    addDemoProposal({
      name,
      description,
      contactId: contactId || null,
      status: "Draft",
      lineItems: lineItems.filter((li) => li.description.trim()),
      totalAmount,
    });

    addToast("Proposal saved as draft", "success");
    router.push("/dashboard/proposals");
  };

  return (
    <div className="p-6 md:p-8">
      <div className="mb-8">
        <h1 className="font-heading text-3xl text-text_primary">New Proposal</h1>
        <p className="text-text_secondary mt-1">Create a new client proposal.</p>
      </div>

      <form onSubmit={handleSubmit} className="max-w-3xl space-y-6">
        <Card>
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-text_primary mb-1.5">Proposal Name</label>
              <input
                required
                value={name}
                onChange={(e) => setName(e.target.value)}
                className="w-full bg-background border border-border rounded-lg px-3 py-2 text-text_primary text-sm focus:outline-none focus:border-primary"
                placeholder="e.g., Phase 1 MVP Development"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-text_primary mb-1.5">Client (optional)</label>
              <select
                value={contactId}
                onChange={(e) => setContactId(e.target.value)}
                className="w-full bg-background border border-border rounded-lg px-3 py-2 text-text_primary text-sm focus:outline-none focus:border-primary"
              >
                <option value="">Select a client...</option>
                {contacts.map((c) => (
                  <option key={c.id} value={c.id}>{c.name} · {c.company}</option>
                ))}
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-text_primary mb-1.5">Description</label>
              <textarea
                required
                rows={3}
                value={description}
                onChange={(e) => setDescription(e.target.value)}
                className="w-full bg-background border border-border rounded-lg px-3 py-2 text-text_primary text-sm focus:outline-none focus:border-primary resize-none"
                placeholder="Project scope and deliverables..."
              />
            </div>
          </div>
        </Card>

        <Card>
          <div className="flex items-center justify-between mb-4">
            <h3 className="font-heading text-lg text-text_primary">Line Items</h3>
            <Button type="button" variant="secondary" size="sm" onClick={addLineItem}>
              + Add Item
            </Button>
          </div>
          <div className="space-y-3">
            {lineItems.map((li, i) => (
              <div key={i} className="flex flex-col sm:flex-row gap-3">
                <input
                  value={li.description}
                  onChange={(e) => updateLineItem(i, "description", e.target.value)}
                  placeholder="Item description"
                  className="flex-1 bg-background border border-border rounded-lg px-3 py-2 text-text_primary text-sm focus:outline-none focus:border-primary"
                />
                <div className="flex gap-2 items-center">
                  <input
                    type="number"
                    min={1}
                    value={li.quantity}
                    onChange={(e) => updateLineItem(i, "quantity", Math.max(1, parseInt(e.target.value) || 1))}
                    className="w-20 bg-background border border-border rounded-lg px-3 py-2 text-text_primary text-sm focus:outline-none focus:border-primary text-center"
                  />
                  <span className="text-text_secondary text-sm">×</span>
                  <input
                    type="number"
                    min={0}
                    value={li.unitPrice}
                    onChange={(e) => updateLineItem(i, "unitPrice", Math.max(0, parseInt(e.target.value) || 0))}
                    className="w-28 bg-background border border-border rounded-lg px-3 py-2 text-text_primary text-sm focus:outline-none focus:border-primary"
                    placeholder="$0"
                  />
                  <button
                    type="button"
                    onClick={() => removeLineItem(i)}
                    className="text-text_secondary hover:text-red-400 transition-colors p-1"
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                    </svg>
                  </button>
                </div>
              </div>
            ))}
          </div>
          <div className="mt-4 pt-4 border-t border-border flex justify-between items-center">
            <span className="text-text_secondary text-sm">Total</span>
            <span className="font-heading text-2xl text-text_primary">${totalAmount.toLocaleString()}</span>
          </div>
        </Card>

        <div className="flex gap-3">
          <Button type="submit" loading={saving} size="lg">
            Save as Draft
          </Button>
          <Button type="button" variant="secondary" size="lg" onClick={() => router.back()}>
            Cancel
          </Button>
        </div>
      </form>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter, useParams } from "next/navigation";
import { getDemoProposal, updateDemoProposal, getDemoContacts } from "@/lib/demo/demo-store";
import { useToastContext } from "@/components/ui/toast";
import { Button } from "@/components/ui/buttons";
import { Card } from "@/components/ui/cards";
import type { DemoProposalLineItem } from "@/lib/demo/demo-store";

export default function EditProposalPage() {
  const router = useRouter();
  const params = useParams();
  const id = params?.id as string;
  const { addToast } = useToastContext();

  const proposal = getDemoProposal(id);
  const contacts = getDemoContacts();

  const [name, setName] = useState("");
  const [description, setDescription] = useState("");
  const [contactId, setContactId] = useState("");
  const [status, setStatus] = useState("Draft");
  const [lineItems, setLineItems] = useState<DemoProposalLineItem[]>([]);
  const [saving, setSaving] = useState(false);
  const [loaded, setLoaded] = useState(false);

  useEffect(() => {
    if (proposal && !loaded) {
      setName(proposal.name);
      setDescription(proposal.description);
      setContactId(proposal.contactId || "");
      setStatus(proposal.status);
      setLineItems([...proposal.lineItems]);
      setLoaded(true);
    }
  }, [proposal, loaded]);

  if (!proposal) {
    return (
      <div className="p-6 md:p-8 text-center">
        <h1 className="font-heading text-2xl text-text_primary mb-2">Proposal Not Found</h1>
        <p className="text-text_secondary mb-4">This proposal doesn&apos;t exist or was deleted.</p>
        <Button onClick={() => router.push("/dashboard/proposals")}>Back to Proposals</Button>
      </div>
    );
  }

  const totalAmount = lineItems.reduce((sum, li) => sum + li.quantity * li.unitPrice, 0);

  const addLineItem = () => {
    setLineItems([...lineItems, { description: "", quantity: 1, unitPrice: 0 }]);
  };

  const removeLineItem = (i: number) => {
    if (lineItems.length <= 1) return;
    setLineItems(lineItems.filter((_, idx) => idx !== i));
  };

  const updateLineItem = (i: number, field: keyof DemoProposalLineItem, value: string | number) => {
    const updated = [...lineItems];
    updated[i] = { ...updated[i], [field]: value };
    setLineItems(updated);
  };

  const handleSave = async () => {
    if (!name.trim()) { addToast("Proposal name is required", "error"); return; }
    setSaving(true);
    updateDemoProposal(id, {
      name,
      description,
      contactId: contactId || null,
      status: status as "Draft" | "Sent" | "Accepted" | "Rejected",
      lineItems: lineItems.filter((li) => li.description.trim()),
      totalAmount,
    });
    addToast("Proposal updated", "success");
    setSaving(false);
  };

  const handleSend = async () => {
    setSaving(true);
    updateDemoProposal(id, { name, description, contactId: contactId || null, status: "Sent", lineItems, totalAmount });
    setStatus("Sent");
    addToast("Proposal marked as sent", "success");
    setSaving(false);
  };

  const contact = contacts.find((c) => c.id === contactId);
  const contactName = contact ? `${contact.name} · ${contact.company}` : "No client selected";

  return (
    <div className="p-6 md:p-8">
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4 mb-8">
        <div>
          <h1 className="font-heading text-3xl text-text_primary">Edit Proposal</h1>
          <p className="text-text_secondary text-sm mt-1">{contactName}</p>
        </div>
        <div className="flex gap-2">
          <Button variant="secondary" size="sm" onClick={() => router.back()}>
            Back
          </Button>
          <Button variant="primary" size="sm" onClick={handleSave} loading={saving}>
            Save Draft
          </Button>
          <Button variant="accent" size="sm" onClick={handleSend} loading={saving} disabled={status === "Sent" || status === "Accepted"}>
            {status === "Sent" ? "Sent ✓" : status === "Accepted" ? "Accepted ✓" : "Send"}
          </Button>
        </div>
      </div>

      <div className="max-w-3xl space-y-6">
        <Card>
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-text_primary mb-1.5">Proposal Name</label>
              <input
                value={name}
                onChange={(e) => setName(e.target.value)}
                className="w-full bg-background border border-border rounded-lg px-3 py-2 text-text_primary text-sm focus:outline-none focus:border-primary"
              />
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-text_primary mb-1.5">Client</label>
                <select
                  value={contactId}
                  onChange={(e) => setContactId(e.target.value)}
                  className="w-full bg-background border border-border rounded-lg px-3 py-2 text-text_primary text-sm focus:outline-none focus:border-primary"
                >
                  <option value="">Select a client...</option>
                  {contacts.map((c) => (
                    <option key={c.id} value={c.id}>{c.name} · {c.company}</option>
                  ))}
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-text_primary mb-1.5">Status</label>
                <select
                  value={status}
                  onChange={(e) => setStatus(e.target.value)}
                  className="w-full bg-background border border-border rounded-lg px-3 py-2 text-text_primary text-sm focus:outline-none focus:border-primary"
                >
                  <option value="Draft">Draft</option>
                  <option value="Sent">Sent</option>
                  <option value="Accepted">Accepted</option>
                  <option value="Rejected">Rejected</option>
                </select>
              </div>
            </div>
            <div>
              <label className="block text-sm font-medium text-text_primary mb-1.5">Description</label>
              <textarea
                rows={3}
                value={description}
                onChange={(e) => setDescription(e.target.value)}
                className="w-full bg-background border border-border rounded-lg px-3 py-2 text-text_primary text-sm focus:outline-none focus:border-primary resize-none"
              />
            </div>
          </div>
        </Card>

        <Card>
          <div className="flex items-center justify-between mb-4">
            <h3 className="font-heading text-lg text-text_primary">Line Items</h3>
            <Button type="button" variant="secondary" size="sm" onClick={addLineItem}>
              + Add Item
            </Button>
          </div>
          <div className="space-y-3">
            {lineItems.map((li, i) => (
              <div key={i} className="flex flex-col sm:flex-row gap-3">
                <input
                  value={li.description}
                  onChange={(e) => updateLineItem(i, "description", e.target.value)}
                  placeholder="Item description"
                  className="flex-1 bg-background border border-border rounded-lg px-3 py-2 text-text_primary text-sm focus:outline-none focus:border-primary"
                />
                <div className="flex gap-2 items-center">
                  <input
                    type="number"
                    min={1}
                    value={li.quantity}
                    onChange={(e) => updateLineItem(i, "quantity", Math.max(1, parseInt(e.target.value) || 1))}
                    className="w-20 bg-background border border-border rounded-lg px-3 py-2 text-text_primary text-sm focus:outline-none focus:border-primary text-center"
                  />
                  <span className="text-text_secondary text-sm">×</span>
                  <input
                    type="number"
                    min={0}
                    value={li.unitPrice}
                    onChange={(e) => updateLineItem(i, "unitPrice", Math.max(0, parseInt(e.target.value) || 0))}
                    className="w-28 bg-background border border-border rounded-lg px-3 py-2 text-text_primary text-sm focus:outline-none focus:border-primary"
                    placeholder="$0"
                  />
                  <button
                    type="button"
                    onClick={() => removeLineItem(i)}
                    className="text-text_secondary hover:text-red-400 transition-colors p-1"
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                    </svg>
                  </button>
                </div>
              </div>
            ))}
          </div>
          <div className="mt-4 pt-4 border-t border-border flex justify-between items-center">
            <span className="text-text_secondary text-sm">Total</span>
            <span className="font-heading text-2xl text-text_primary">${totalAmount.toLocaleString()}</span>
          </div>
        </Card>
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { getDemoIntakes, addDemoIntake, addDemoContact } from "@/lib/demo/demo-store";
import { useToastContext } from "@/components/ui/toast";
import { Button } from "@/components/ui/buttons";
import { Card } from "@/components/ui/cards";
import Link from "next/link";

export default function IntakePage() {
  const router = useRouter();
  const { addToast } = useToastContext();
  const [intakes, setIntakes] = useState(() => getDemoIntakes());
  const [showForm, setShowForm] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [saving, setSaving] = useState(false);

  const [form, setForm] = useState({
    companyName: "",
    contactName: "",
    email: "",
    phone: "",
    industry: "",
    projectType: "",
    budgetRange: "",
    timeline: "",
    currentChannels: "",
    primaryGoal: "",
    additionalInfo: "",
  });

  const updateField = (field: string, value: string) => {
    setForm((prev) => ({ ...prev, [field]: value }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.companyName || !form.contactName || !form.email || !form.primaryGoal) {
      addToast("Please fill in all required fields", "error");
      return;
    }
    setSaving(true);

    // Create contact from intake
    const contact = addDemoContact({
      name: form.contactName,
      email: form.email,
      company: form.companyName,
      phone: form.phone,
      source: "Intake Form",
      status: "Lead",
      tags: [form.industry, form.projectType].filter(Boolean),
      notes: [{ text: `Intake submitted. Goal: ${form.primaryGoal}`, date: new Date().toISOString() }],
    });

    addDemoIntake({
      contactId: contact.id,
      templateId: "t-standard",
      status: "New",
      answers: [
        { question: "Company Name", answer: form.companyName },
        { question: "Contact Name", answer: form.contactName },
        { question: "Email", answer: form.email },
        { question: "Industry", answer: form.industry },
        { question: "Project Type", answer: form.projectType },
        { question: "Budget Range", answer: form.budgetRange },
        { question: "Timeline", answer: form.timeline },
        { question: "Current Channels", answer: form.currentChannels },
        { question: "Primary Goal", answer: form.primaryGoal },
      ],
    });

    setIntakes(getDemoIntakes());
    setSaving(false);
    setSubmitted(true);
    addToast("Intake submitted! Contact created.", "success");
  };

  if (submitted) {
    return (
      <div className="p-6 md:p-8 flex items-center justify-center min-h-[60vh]">
        <div className="text-center max-w-md">
          <div className="text-5xl mb-4">✓</div>
          <h2 className="font-heading text-3xl text-text_primary">Intake Submitted!</h2>
          <p className="text-text_secondary mt-2">
            Thanks, {form.contactName}! A new contact has been created for {form.companyName}.
          </p>
          <div className="flex gap-3 justify-center mt-6">
            <Link href="/dashboard/contacts">
              <Button variant="primary" size="sm">View Contacts</Button>
            </Link>
            <Link href="/dashboard/proposals/new">
              <Button variant="accent" size="sm">Create Proposal</Button>
            </Link>
            <Button
              variant="secondary"
              size="sm"
              onClick={() => {
                setForm({ companyName: "", contactName: "", email: "", phone: "", industry: "", projectType: "", budgetRange: "", timeline: "", currentChannels: "", primaryGoal: "", additionalInfo: "" });
                setSubmitted(false);
              }}
            >
              New Intake
            </Button>
          </div>
        </div>
      </div>
    );
  }

  if (!showForm) {
    const newIntakes = intakes.filter((i) => i.status === "New");
    const reviewedIntakes = intakes.filter((i) => i.status === "Reviewed");
    const convertedIntakes = intakes.filter((i) => i.status === "Converted");

    return (
      <div className="p-6 md:p-8">
        <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4 mb-8">
          <div>
            <h1 className="font-heading text-3xl text-text_primary">Intake</h1>
            <p className="text-text_secondary mt-1">Client intake forms and submissions.</p>
          </div>
          <Button onClick={() => setShowForm(true)}>+ New Intake</Button>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8">
          <div className="bg-surface border border-primary/30 rounded-xl p-5">
            <p className="text-text_secondary text-sm">New</p>
            <p className="font-heading text-3xl text-primary mt-1">{newIntakes.length}</p>
          </div>
          <div className="bg-surface border border-accent/30 rounded-xl p-5">
            <p className="text-text_secondary text-sm">Reviewed</p>
            <p className="font-heading text-3xl text-accent mt-1">{reviewedIntakes.length}</p>
          </div>
          <div className="bg-surface border border-green-500/30 rounded-xl p-5">
            <p className="text-text_secondary text-sm">Converted</p>
            <p className="font-heading text-3xl text-green-400 mt-1">{convertedIntakes.length}</p>
          </div>
        </div>

        <div className="space-y-4">
          {intakes.length === 0 && (
            <div className="text-center py-12 text-text_secondary">
              No intakes yet. Click &quot;+ New Intake&quot; to get started.
            </div>
          )}
          {intakes.map((intake) => (
            <Card key={intake.id}>
              <div className="flex items-start justify-between">
                <div>
                  <p className="font-medium text-text_primary text-sm">
                    {intake.answers.find((a) => a.question === "Company Name")?.answer || "Unknown Company"}
                  </p>
                  <p className="text-text_secondary text-xs mt-0.5">
                    {intake.answers.find((a) => a.question === "Primary Goal")?.answer || "No goal specified"}
                  </p>
                  <p className="text-text_secondary text-xs mt-1">
                    Submitted {new Date(intake.createdAt).toLocaleDateString()}
                  </p>
                </div>
                <span className={`text-xs px-2.5 py-1 rounded-full border ${
                  intake.status === "New" ? "bg-primary/10 text-primary border-primary/30" :
                  intake.status === "Reviewed" ? "bg-accent/10 text-accent border-accent/30" :
                  "bg-green-500/10 text-green-400 border-green-500/30"
                }`}>
                  {intake.status}
                </span>
              </div>
            </Card>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="p-6 md:p-8">
      <div className="mb-8">
        <h1 className="font-heading text-3xl text-text_primary">New Intake</h1>
        <p className="text-text_secondary mt-1">Fill out the client intake form.</p>
      </div>

      <form onSubmit={handleSubmit} className="max-w-3xl space-y-8">
        <Card>
          <h3 className="font-heading text-lg text-text_primary border-b border-border pb-3 mb-4">Business Information</h3>
          <div className="space-y-4">
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-text_primary mb-1.5">Company Name *</label>
                <input required value={form.companyName} onChange={(e) => updateField("companyName", e.target.value)}
                  className="w-full bg-background border border-border rounded-lg px-3 py-2 text-text_primary text-sm focus:outline-none focus:border-primary" placeholder="Acme Inc." />
              </div>
              <div>
                <label className="block text-sm font-medium text-text_primary mb-1.5">Contact Name *</label>
