"use client";

import { useState, useCallback } from "react";
import { isDemoMode } from "@/lib/demo/demo-store";

interface UseApiOptions {
  method?: "GET" | "POST" | "PUT" | "PATCH" | "DELETE";
  body?: unknown;
}

interface UseApiState<T> {
  data: T | null;
  loading: boolean;
  error: string | null;
}

export function useApi<T = unknown>() {
  const [state, setState] = useState<UseApiState<T>>({
    data: null,
    loading: false,
    error: null,
  });

  const request = useCallback(async (endpoint: string, options: UseApiOptions = {}) => {
    if (isDemoMode()) {
      // In demo mode, API calls are simulated. Return null data.
      setState({ data: null, loading: false, error: null });
      return { data: null, error: null };
    }

    setState((prev) => ({ ...prev, loading: true, error: null }));
    try {
      const res = await fetch(endpoint, {
        method: options.method || "GET",
        headers: { "Content-Type": "application/json" },
        body: options.body ? JSON.stringify(options.body) : undefined,
      });
      if (!res.ok) {
        const errText = await res.text();
        throw new Error(errText || `HTTP ${res.status}`);
      }
      const data = await res.json();
      setState({ data, loading: false, error: null });
      return { data, error: null };
    } catch (err) {
      const message = err instanceof Error ? err.message : "API request failed";
      setState({ data: null, loading: false, error: message });
      return { data: null, error: message };
    }
  }, []);

  return { ...state, request };
}

"use client";

import { useRouter } from "next/navigation";
import { useState } from "react";
import { signIn } from "@/lib/supabase/auth";
import { useToastContext } from "@/components/ui/toast";
import { useDemoAuth } from "@/lib/demo/demo-auth";
import { Button } from "@/components/ui/buttons";
import Link from "next/link";

export default function LoginPage() {
  const router = useRouter();
  const { addToast } = useToastContext();
  const { isDemo, oneClickDemo } = useDemoAuth();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setLoading(true);

    const { error: err } = await signIn(email, password);

    if (err) {
      setError(err);
      addToast(err, "error");
      setLoading(false);
    } else {
      addToast("Signed in successfully", "success");
      router.push("/dashboard");
      router.refresh();
    }
  };

  const handleDemoLogin = async () => {
    setLoading(true);
    if (isDemo) {
      const { error: err } = await oneClickDemo();
      if (err) {
        setError(err);
        addToast(err, "error");
        setLoading(false);
      } else {
        addToast("Signed in with demo account", "success");
        router.push("/dashboard");
        router.refresh();
      }
    } else {
      setEmail("demo@demo.app");
      setPassword("demo123");
      const { error: err } = await signIn("demo@demo.app", "demo123");
      if (err) {
        setError(err);
        addToast(err, "error");
        setLoading(false);
      } else {
        addToast("Signed in successfully", "success");
        router.push("/dashboard");
        router.refresh();
      }
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-background px-4">
      <div className="w-full max-w-md">
        <div className="text-center mb-8">
          <Link href="/" className="font-heading text-3xl text-primary">
            ATLASHAVEN
          </Link>
          <p className="mt-2 text-text_secondary">Sign in to your account</p>
        </div>
        <div className="bg-surface border border-border rounded-xl p-8">
          <form onSubmit={handleSubmit} className="space-y-5">
            {error && (
              <div className="bg-red-500/10 border border-red-500/30 rounded-lg p-3 text-red-400 text-sm">
                {error}
              </div>
            )}
            <div>
              <label htmlFor="email" className="block text-sm font-medium text-text_primary mb-1.5">
                Email
              </label>
              <input
                id="email"
                type="email"
                required
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="w-full bg-background border border-border rounded-lg px-3 py-2 text-text_primary text-sm placeholder:text-text_secondary focus:outline-none focus:border-primary transition-colors"
                placeholder="you@company.com"
              />
            </div>
            <div>
              <div className="flex items-center justify-between mb-1.5">
                <label htmlFor="password" className="block text-sm font-medium text-text_primary">
                  Password
                </label>
                <Link href="/reset-password/request" className="text-xs text-primary hover:underline">
                  Forgot password?
                </Link>
              </div>
              <input
                id="password"
                type="password"
                required
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full bg-background border border-border rounded-lg px-3 py-2 text-text_primary text-sm placeholder:text-text_secondary focus:outline-none focus:border-primary transition-colors"
                placeholder="••••••••"
              />
            </div>
            <Button type="submit" loading={loading} className="w-full">
              Sign In
            </Button>

            {isDemo && (
              <Button
                type="button"
                variant="accent"
                onClick={handleDemoLogin}
                loading={loading}
                className="w-full"
              >
                One-Click Demo Access
              </Button>
            )}

            <p className="text-text_secondary text-sm text-center">
              Don&apos;t have an account?{" "}
              <Link href="/signup" className="text-primary hover:underline">
                Sign up
              </Link>
            </p>
          </form>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useRouter } from "next/navigation";
import { useState } from "react";
import { signUp } from "@/lib/supabase/auth";
import { useToastContext } from "@/components/ui/toast";
import { useDemoAuth } from "@/lib/demo/demo-auth";
import Link from "next/link";

export default function SignupPage() {
  const router = useRouter();
  const { addToast } = useToastContext();
  const { isDemo } = useDemoAuth();
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setLoading(true);

    const { error: err } = await signUp(email, password, name);

    if (err) {
      setError(err);
      addToast(err, "error");
      setLoading(false);
    } else {
      addToast("Account created. Check your email to confirm.", "success");
      if (isDemo) {
        router.push("/dashboard");
      }
      router.refresh();
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-background px-4">
      <div className="w-full max-w-md">
        <div className="text-center mb-8">
          <Link href="/" className="font-heading text-3xl text-primary">
            ATLASHAVEN
          </Link>
          <p className="mt-2 text-text_secondary">Create your account</p>
        </div>
        <div className="bg-surface border border-border rounded-xl p-8">
          <form onSubmit={handleSubmit} className="space-y-5">
            {error && (
              <div className="bg-red-500/10 border border-red-500/30 rounded-lg p-3 text-red-400 text-sm">
                {error}
              </div>
            )}
            <div>
              <label htmlFor="name" className="block text-sm font-medium text-text_primary mb-1.5">
                Full Name
              </label>
              <input
                id="name"
                type="text"
                required
                value={name}
                onChange={(e) => setName(e.target.value)}
                className="w-full bg-background border border-border rounded-lg px-3 py-2 text-text_primary text-sm placeholder:text-text_secondary focus:outline-none focus:border-primary transition-colors"
                placeholder="Alex Rivera"
              />
            </div>
            <div>
              <label htmlFor="email" className="block text-sm font-medium text-text_primary mb-1.5">
                Email
              </label>
              <input
                id="email"
                type="email"
                required
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="w-full bg-background border border-border rounded-lg px-3 py-2 text-text_primary text-sm placeholder:text-text_secondary focus:outline-none focus:border-primary transition-colors"
                placeholder="you@company.com"
              />
            </div>
            <div>
              <label htmlFor="password" className="block text-sm font-medium text-text_primary mb-1.5">
                Password
              </label>
              <input
                id="password"
                type="password"
                required
                minLength={6}
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full bg-background border border-border rounded-lg px-3 py-2 text-text_primary text-sm placeholder:text-text_secondary focus:outline-none focus:border-primary transition-colors"
                placeholder="••••••••"
              />
            </div>
            <button
              type="submit"
              disabled={loading}
              className="w-full bg-primary text-background py-3 rounded-lg font-semibold hover:bg-primary/90 transition-colors disabled:opacity-50 inline-flex items-center justify-center gap-2"
            >
              {loading && (
                <svg className="animate-spin h-4 w-4" viewBox="0 0 24 24" fill="none">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" />
                </svg>
              )}
              {loading ? "Creating account..." : "Create Account"}
            </button>

            {isDemo && (
              <div className="bg-accent/10 border border-accent/30 rounded-lg p-3 text-accent text-xs">
                Demo mode: sign up is simulated. Use the sign-in page for one-click demo access.
              </div>
            )}

            <p className="text-text_secondary text-sm text-center">
              Already have an account?{" "}
              <Link href="/login" className="text-primary hover:underline">
                Sign in
              </Link>
            </p>
          </form>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import Link from "next/link";
import { getDemoContacts, addDemoContact, type DemoContact } from "@/lib/demo/demo-store";
import { useToastContext } from "@/components/ui/toast";
import { Button } from "@/components/ui/buttons";
import { Card } from "@/components/ui/cards";
import { Modal } from "@/components/ui/modal";

const statusColors: Record<string, string> = {
  Active: "bg-green-500/10 text-green-400 border-green-500/30",
  Lead: "bg-accent/10 text-accent border-accent/30",
  Client: "bg-primary/10 text-primary border-primary/30",
  Inactive: "bg-text_secondary/10 text-text_secondary border-text_secondary/30",
};

export default function ClientsPage() {
  const { addToast } = useToastContext();
  const [contacts, setContacts] = useState(() => getDemoContacts());
  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState<string>("All");
  const [selected, setSelected] = useState<DemoContact | null>(null);
  const [showAdd, setShowAdd] = useState(false);

  const [newName, setNewName] = useState("");
  const [newEmail, setNewEmail] = useState("");
  const [newCompany, setNewCompany] = useState("");
  const [newPhone, setNewPhone] = useState("");
  const [newSource, setNewSource] = useState("");
  const [newStatus, setNewStatus] = useState<DemoContact["status"]>("Lead");

  const filtered = contacts.filter((c) => {
    const matchesSearch =
      c.name.toLowerCase().includes(search.toLowerCase()) ||
      c.company.toLowerCase().includes(search.toLowerCase()) ||
      c.email.toLowerCase().includes(search.toLowerCase());
    const matchesStatus = statusFilter === "All" || c.status === statusFilter;
    return matchesSearch && matchesStatus;
  });

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newName || !newCompany) {
      addToast("Name and company are required", "error");
      return;
    }
    const c = addDemoContact({
      name: newName,
      email: newEmail,
      company: newCompany,
      phone: newPhone,
      source: newSource || "Manual",
      status: newStatus,
      tags: [],
      notes: [],
    });
    setContacts(getDemoContacts());
    setShowAdd(false);
    setNewName(""); setNewEmail(""); setNewCompany(""); setNewPhone(""); setNewSource("");
    addToast(`${c.name} added as client`, "success");
  };

  const statusCounts = {
    total: contacts.length,
    active: contacts.filter((c) => c.status === "Active").length,
    lead: contacts.filter((c) => c.status === "Lead").length,
    client: contacts.filter((c) => c.status === "Client").length,
  };

  return (
    <div className="p-6 md:p-8">
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4 mb-6">
        <div>
          <h1 className="font-heading text-3xl text-text_primary">Clients</h1>
          <p className="text-text_secondary mt-1">Manage your client portfolio and relationships.</p>
        </div>
        <div className="flex gap-2">
          <Link href="/dashboard/proposals/new">
            <Button variant="primary" size="sm">+ New Proposal</Button>
          </Link>
          <Button variant="accent" size="sm" onClick={() => setShowAdd(true)}>+ Add Client</Button>
        </div>
      </div>

      {/* Quick stats */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 mb-6">
        {[
          { label: "All Clients", value: statusCounts.total, color: "text-text_primary" },
          { label: "Active", value: statusCounts.active, color: "text-green-400" },
          { label: "Leads", value: statusCounts.lead, color: "text-accent" },
          { label: "Clients", value: statusCounts.client, color: "text-primary" },
        ].map((s) => (
          <div key={s.label} className="bg-surface border border-border rounded-xl p-4 text-center">
            <p className={`font-heading text-2xl ${s.color}`}>{s.value}</p>
            <p className="text-text_secondary text-xs mt-0.5">{s.label}</p>
          </div>
        ))}
      </div>

      <div className="flex flex-col sm:flex-row gap-3 mb-6">
        <input
          type="text"
          placeholder="Search clients by name, company, or email..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="flex-1 bg-surface border border-border rounded-lg px-4 py-2 text-text_primary text-sm placeholder:text-text_secondary focus:outline-none focus:border-primary transition-colors"
        />
        <select
          value={statusFilter}
          onChange={(e) => setStatusFilter(e.target.value)}
          className="bg-surface border border-border rounded-lg px-4 py-2 text-text_primary text-sm focus:outline-none focus:border-primary"
        >
          <option value="All">All Statuses</option>
          <option value="Active">Active</option>
          <option value="Lead">Lead</option>
          <option value="Client">Client</option>
          <option value="Inactive">Inactive</option>
        </select>
      </div>

      <Card padding="sm">
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="border-b border-border">
                <th className="text-left px-5 py-3 text-xs font-semibold text-text_secondary uppercase tracking-wider">Name</th>
                <th className="text-left px-5 py-3 text-xs font-semibold text-text_secondary uppercase tracking-wider">Company</th>
                <th className="text-left px-5 py-3 text-xs font-semibold text-text_secondary uppercase tracking-wider hidden sm:table-cell">Email</th>
                <th className="text-left px-5 py-3 text-xs font-semibold text-text_secondary uppercase tracking-wider">Status</th>
                <th className="text-left px-5 py-3 text-xs font-semibold text-text_secondary uppercase tracking-wider hidden lg:table-cell">Source</th>
              </tr>
            </thead>
            <tbody>
              {filtered.map((c) => (
                <tr
                  key={c.id}
                  onClick={() => setSelected(c)}
                  className="border-b border-border last:border-0 hover:bg-background/50 cursor-pointer transition-colors"
                >
                  <td className="px-5 py-3.5">
                    <div className="flex items-center gap-3">
                      <div className="w-8 h-8 rounded-full bg-primary/20 flex items-center justify-center text-primary font-semibold text-xs shrink-0">
                        {c.name.charAt(0)}
                      </div>
                      <span className="text-text_primary text-sm font-medium">{c.name}</span>
                    </div>
                  </td>
                  <td className="px-5 py-3.5 text-text_secondary text-sm">{c.company}</td>
                  <td className="px-5 py-3.5 text-text_secondary text-sm hidden sm:table-cell">{c.email}</td>
                  <td className="px-5 py-3.5">
                    <span className={`inline-block text-xs px-2.5 py-1 rounded-full border font-medium ${statusColors[c.status]}`}>
                      {c.status}
                    </span>
                  </td>
                  <td className="px-5 py-3.5 text-text_secondary text-sm hidden lg:table-cell">{c.source}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        {filtered.length === 0 && (
          <div className="text-center py-16 text-text_secondary">
            <p className="text-lg mb-1">No clients found</p>
            <p className="text-sm">Try adjusting your search or filters.</p>
          </div>
        )}
      </Card>

      {/* Detail Drawer/Modal */}
      <Modal open={!!selected} onClose={() => setSelected(null)} title="Client Details" size="lg">
        {selected && (
          <div className="space-y-5">
            <div className="flex items-start gap-4">
              <div className="w-14 h-14 rounded-full bg-primary/20 flex items-center justify-center text-primary font-bold text-xl shrink-0">
                {selected.name.charAt(0)}
              </div>
              <div className="flex-1 min-w-0">
                <h3 className="font-heading text-xl text-text_primary">{selected.name}</h3>
                <p className="text-text_secondary text-sm">{selected.company}</p>
                <p className="text-text_secondary text-sm">{selected.email}</p>
                {selected.phone && <p className="text-text_secondary text-sm">{selected.phone}</p>}
              </div>
              <span className={`text-xs px-2.5 py-1 rounded-full border shrink-0 ${statusColors[selected.status]}`}>
                {selected.status}
              </span>
            </div>

            <div className="grid grid-cols-2 gap-3 text-sm">
              <div className="bg-background border border-border rounded-lg p-3">
                <span className="text-text_secondary text-xs">Source</span>
                <p className="text-text_primary font-medium">{selected.source}</p>
              </div>
              <div className="bg-background border border-border rounded-lg p-3">
                <span className="text-text_secondary text-xs">Client Since</span>
                <p className="text-text_primary font-medium">{new Date(selected.createdAt).toLocaleDateString()}</p>
              </div>
            </div>

            {selected.tags.length > 0 && (
              <div>
                <span className="text-text_secondary text-xs block mb-2">Tags</span>
                <div className="flex flex-wrap gap-2">
                  {selected.tags.map((t) => (
                    <span key={t} className="text-xs bg-background text-text_secondary px-2.5 py-1 rounded-full border border-border">
                      {t}
                    </span>
                  ))}
                </div>
              </div>
            )}

            {selected.notes.length > 0 && (
              <div>
                <span className="text-text_secondary text-xs block mb-2">Activity</span>
                <div className="space-y-2 max-h-48 overflow-y-auto">
                  {selected.notes.map((n, i) => (
                    <div key={i} className="bg-background border border-border rounded-lg p-3">
                      <p className="text-text_primary text-sm">{n.text}</p>
                      <p className="text-text_secondary text-xs mt-1">{new Date(n.date).toLocaleDateString()}</p>
                    </div>
                  ))}
                </div>
              </div>
            )}

            <div className="flex gap-2 pt-1">
              <Link
                href={`/dashboard/proposals/new?contactId=${selected.id}`}
                className="inline-flex items-center justify-center bg-primary text-background px-4 py-2.5 rounded-lg text-sm font-semibold hover:bg-primary/90 transition-colors"
              >
                Create Proposal
              </Link>
              <Link
                href="/dashboard/intake"
                className="inline-flex items-center justify-center border border-border text-text_primary px-4 py-2.5 rounded-lg text-sm font-medium hover:bg-surface transition-colors"
              >
                New Intake
              </Link>
              <Button variant="secondary" onClick={() => setSelected(null)}>Close</Button>
            </div>
          </div>
        )}
      </Modal>

      {/* Add Client Modal */}
      <Modal open={showAdd} onClose={() => setShowAdd(false)} title="Add New Client">
        <form onSubmit={handleAdd} className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-text_primary mb-1.5">Full Name *</label>
            <input
              required
              value={newName}
              onChange={(e) => setNewName(e.target.value)}
              className="w-full bg-background border border-border rounded-lg px-3 py-2 text-text_primary text-sm focus:outline-none focus:border-primary placeholder:text-text_secondary"
              placeholder="Jane Smith"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-text_primary mb-1.5">Company *</label>
            <input
              required
              value={newCompany}
              onChange={(e) => setNewCompany(e.target.value)}
              className="w-full bg-background border border-border rounded-lg px-3 py-2 text-text_primary text-sm focus:outline-none focus:border-primary placeholder:text-text_secondary"
              placeholder="Acme Inc."
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-text_primary mb-1.5">Email</label>
            <input
              type="email"
              value={newEmail}
              onChange={(e) => setNewEmail(e.target.value)}
              className="w-full bg-background border border-border rounded-lg px-3 py-2 text-text_primary text-sm focus:outline-none focus:border-primary placeholder:text-text_secondary"
              placeholder="jane@acme.com"
            />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-text_primary mb-1.5">Phone</label>
              <input
                value={newPhone}
                onChange={(e) => setNewPhone(e.target.value)}
                className="w-full bg-background border border-border rounded-lg px-3 py-2 text-text_primary text-sm focus:outline-none focus:border-primary placeholder:text-text_secondary"
                placeholder="+1 555-0100"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-text_primary mb-1.5">Source</label>
              <input
                value={newSource}
                onChange={(e) => setNewSource(e.target.value)}
                className="w-full bg-background border border-border rounded-lg px-3 py-2 text-text_primary text-sm focus:outline-none focus:border-primary placeholder:text-text_secondary"
                placeholder="Referral, Website..."
              />
            </div>
          </div>
          <div>
            <label className="block text-sm font-medium text-text_primary mb-1.5">Status</label>
            <select
              value={newStatus}
              onChange={(e) => setNewStatus(e.target.value as DemoContact["status"])}
              className="w-full bg-background border border-border rounded-lg px-3 py-2 text-text_primary text-sm focus:outline-none focus:border-primary"
            >
              <option value="Lead">Lead</option>
              <option value="Active">Active</option>
              <option value="Client">Client</option>
              <option value="Inactive">Inactive</option>
            </select>
          </div>
          <Button type="submit" className="w-full">Add Client</Button>
        </form>
      </Modal>
    </div>
  );
}
